/* ProductCardsSection - structured, consistent media rendering */

.os-product-section {
	background: #f9f9f7;
}

.os-product-title {
	font-family: Montserrat, sans-serif;
	font-size: 36px;
	font-weight: 700;
	color: #333;
	line-height: 1.2;
	letter-spacing: -0.01em;
	text-align: center;
	margin-bottom: 48px;
}

.os-product-grid {
	display: grid;
	grid-template-columns: 1fr;
	gap: 24px;
}

@media (min-width: 768px) {
	.os-product-grid {
		grid-template-columns: repeat(3, minmax(0, 1fr));
	}
}

.os-card {
	background: #fff;
	border: 1px solid #e5e7eb;
	border-radius: 16px;
	overflow: hidden;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
	height: 100%;
	display: flex;
	flex-direction: column;
}

.os-media {
	position: relative;
	background: #f5f5f5;
	border-radius: 16px 16px 0 0;
	/* Consistent aspect ratio so screenshots align */
	aspect-ratio: 16 / 10;
	overflow: hidden;
}

/* If you still want different heights per card, keep inline style height.
   If you prefer consistent layout, remove inline height and rely on aspect-ratio. */

.os-mediaImage {
	width: 100%;
	height: 100%;
	display: block;
	object-fit: cover;
}

.os-mediaOverlay {
	position: absolute;
	inset: 0;
	background: linear-gradient(180deg, rgba(0, 0, 0, 0.18) 0%, rgba(0, 0, 0, 0) 36%),
		linear-gradient(0deg, rgba(0, 0, 0, 0.1) 0%, rgba(0, 0, 0, 0) 40%);
	pointer-events: none;
}

.os-badge {
	position: absolute;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	width: 50px;
	height: 50px;
	border-radius: 9999px;
	background: rgba(255, 255, 255, 0.92);
	box-shadow: 0 6px 18px rgba(0, 0, 0, 0.14);
	backdrop-filter: blur(8px);
}

.os-badgeIcon {
	color: #2d472c;
}

.os-cardBody {
	padding: 24px;
	text-align: center;
	display: flex;
	flex-direction: column;
	gap: 16px;
	flex: 1;
}

.os-cardTitle {
	font-family: Montserrat, sans-serif;
	font-size: 20px;
	font-weight: 700;
	color: #333;
}

.os-cardDesc {
	font-size: 14px;
	color: #6b7280;
	line-height: 1.6;
}

.os-cardFooter {
	margin-top: auto;
	padding-top: 16px;
}

.os-cardCta {
	width: 100%;
	height: 44px;
	border-radius: 8px;
	font-size: 14px;
	font-weight: 600;
	background: #2d472c;
	color: #fff;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	gap: 8px;
	transition: opacity 0.2s ease;
}

.os-cardCta:hover {
	opacity: 0.9;
}

